34	use std::path::{Path, PathBuf};
35	use std::process::Command;
36	use std::sync::OnceLock;
37	
38	static RBTDRX_IS_CYGWIN: OnceLock<bool> = OnceLock::new();
39	
40	/// Detect whether we're running under a Cygwin-spawned shell environment.
41	///
42	/// On Cygwin, the launching bash exports `OSTYPE=cygwin` to spawned
43	/// processes — including Windows-native binaries like a
44	/// `x86_64-pc-windows-gnu` theurge. Result is cached for binary lifetime.
45	pub fn rbtdrx_is_cygwin() -> bool {
46	    *RBTDRX_IS_CYGWIN.get_or_init(|| {
47	        matches!(std::env::var("OSTYPE").as_deref(), Ok("cygwin"))
48	    })
49	}
