51	/// Convert a path string from POSIX form (as Cygwin bash uses) to native
52	/// PathBuf form (as the Windows OS uses). On non-Cygwin platforms, identity.
53	///
54	/// Returns `Err` only when running on Cygwin AND the path is not a recognised
55	/// fast-path shape AND the `cygpath` fallback fails — i.e., the platform
56	/// claims Cygwin via OSTYPE but cygpath is unreachable.
57	pub fn rbtdrx_posix_to_native(s: &str) -> Result<PathBuf, String> {
58	    rbtdrx_posix_to_native_for(s, rbtdrx_is_cygwin())
59	}
60	
61	/// Convert a Path from native form to POSIX form suitable for embedding in
62	/// a Cygwin bash script or for passing as an env var to a Cygwin-bash
63	/// tabtarget. On non-Cygwin platforms, returns the path's display form.
64	///
65	/// Best-effort: on Cygwin, falls back to `cygpath -u` for unrecognised
66	/// native shapes; if cygpath fails the original display form is returned
67	/// rather than failing the caller. Outflow sites (env vars, format!
68	/// interpolations) cannot meaningfully propagate errors mid-script.
