75	pub(crate) fn rbtdrx_posix_to_native_for(s: &str, is_cygwin: bool) -> Result<PathBuf, String> {
76	    if !is_cygwin {
77	        return Ok(PathBuf::from(s));
78	    }
79	
80	    // Fast path: /cygdrive/X/foo → X:\foo
81	    if let Some(native) = rbtdrx_cygdrive_to_native(s) {
82	        return Ok(native);
83	    }
84	
85	    // Already native Windows form (drive-letter prefix)
86	    if rbtdrx_looks_native_windows(s) {
87	        return Ok(PathBuf::from(s));
88	    }
89	
90	    // Slow path: bare POSIX (/home/..., /tmp/...) needs cygpath
91	    rbtdrx_cygpath(s, "-w")
92	        .map(PathBuf::from)
93	        .ok_or_else(|| format!("rbtdrx: cygpath -w failed for '{}'", s))
94	}
