161	pub(crate) fn rbtdrx_looks_native_windows(s: &str) -> bool {
162	    let bytes = s.as_bytes();
163	    bytes.len() >= 2 && bytes[0].is_ascii_alphabetic() && bytes[1] == b':'
164	}
