166	// ── cygpath fallback ───────────────────────────────────────────────────
167	
168	fn rbtdrx_cygpath(input: &str, flag: &str) -> Option<String> {
169	    let output = Command::new("cygpath").arg(flag).arg(input).output().ok()?;
170	    if !output.status.success() {
171	        return None;
172	    }
173	    let s = String::from_utf8(output.stdout).ok()?;
174	    Some(s.trim_end_matches(['\n', '\r']).to_string())
